import * as THREE from 'three'
import { Suspense, useRef } from 'react'
import { Canvas, useFrame, useThree } from '@react-three/fiber'
import { Preload, Image as ImageImpl } from '@react-three/drei'
import { ScrollControls, Scroll, useScroll } from './ScrollControls.tsx';
import { BrowserRouter, Routes, Route } from "react-router-dom";
import './App.css';

function Image(props) {
  const ref = useRef()
  const group = useRef()
  const data = useScroll()
  useFrame((state, delta) => {
    group.current.position.z = THREE.MathUtils.damp(group.current.position.z, Math.max(0, data.delta * 50), 4, delta)
    ref.current.material.grayscale = THREE.MathUtils.damp(ref.current.material.grayscale, Math.max(0, 1 - data.delta * 1000), 4, delta)
  })
  return (
    <group ref={group}>
      <ImageImpl ref={ref} {...props} />
    </group>
  )
}

function Page({ m = 0.4, urls, ...props }) {
  const { width } = useThree((state) => state.viewport)
  const w = width < 100 ? 1.5 / 3 : 1 / 3
  return (
    <group {...props}>
      <Image position={[-width * w, 0, -1]} scale={[width * w - m * 2, 5, 1]} url={urls[0]} />
      <Image position={[0, 0, 0]} scale={[width * w - m * 2, 5, 1]} url={urls[1]} />
      <Image position={[width * w, 0, 1]} scale={[width * w - m * 2, 5, 1]} url={urls[2]} />
    </group>
  )
}

function Pages() {
  const { width } = useThree((state) => state.viewport)
  return (
    <>
      <Page position={[-width * 1, 0, 0]} urls={['/Img4.jpg', '/trip2.jpg', '/trip3.jpg']} />
      <Page position={[width * 0, 0, 0]} urls={['/Img4.jpg', '/img2.jpg', '/img3.jpg']} />
      <Page position={[width * 1, 0, 0]} urls={['/img4.jpg', '/img5.jpg', '/img6.jpg']} />
      <Page position={[width * 2, 0, 0]} urls={['/Img4.jpg', '/trip2.jpg', '/trip3.jpg']} />
      <Page position={[width * 3, 0, 0]} urls={['/Img4.jpg', '/img2.jpg', '/img3.jpg']} />
      <Page position={[width * 4, 0, 0]} urls={['/img4.jpg', '/img5.jpg', '/img6.jpg']} />
    </>
  )
}

export default function App() {
  return (
    <>
      <BrowserRouter>
        <Routes>
          <Route path="/" element={
            <Canvas gl={{ antialias: false }} dpr={[1, 1.5]}>
              <Suspense fallback={null}>
                <ScrollControls infinite horizontal damping={4} pages={4} distance={1}>
                  <Scroll>
                    <Pages />
                  </Scroll>
                  <Scroll html>
                    <h1 className='font' style={{ position: 'absolute', top: '-15vh', left: '25vw' }}>generative</h1>
                    <h1 className='font' style={{ position: 'absolute', top: '-15vh', left: '125vw' }}>adversial</h1>
                    <h1 className='font' style={{ position: 'absolute', top: '-15vh', left: '225vw' }}>networks</h1>
                    <a className='fonts' href="https://praful-vats.github.io/xense/" style={{ position: 'absolute', top: '50vh', left: '40vw' }}>xense&#x1F86D;</a>
                    <a className='fonts' href="https://praful-vats.github.io/xyle/" style={{ position: 'absolute', top: '50vh', left: '84vw' }}>xyle&#x1F86D;</a>
                    <a className='fonts' href="/xf" style={{ position: 'absolute', top: '50vh', left: '133vw' }}>xideo&#x1F86D;</a>
                    <a className='fonts' href="/xf" style={{ position: 'absolute', top: '50vh', left: '190vw' }}>xext&#x1F86D;</a>
                    <a className='fonts' href="/xf" style={{ position: 'absolute', top: '50vh', left: '240vw' }}>xpose&#x1F86D;</a>
                    <a className='fonts' href="/xf" style={{ position: 'absolute', top: '50vh', left: '287vw' }}>xandom&#x1F86D;</a>
                  </Scroll>
                </ScrollControls>
                <Preload />
              </Suspense>
            </Canvas>
          } />
        </Routes>
      </BrowserRouter>
    </>
  )
}
